const configs = $input.all().map(i => i.json);
const tokenConfig = configs.find(c => c.key === 'tradelocker_access_token');
const tradingEnabled = configs.find(c => c.key === 'is_trading_enabled');

if (!tradingEnabled || tradingEnabled.value === false || tradingEnabled.value === 'false') {
  return [{ json: { skip: true, reason: 'Trading is disabled' } }];
}

if (!tokenConfig) {
  return [{ json: { skip: true, reason: 'No access token' } }];
}

let accessToken = tokenConfig.value;
try { accessToken = JSON.parse(accessToken); } catch(e) {}

return [{ json: { skip: false, accessToken, allConfigs: configs } }];

// ============================================
// POSITION SYNC LOGIC v2.7 - Champion decision takes priority
// Champion's current round decision takes priority over opened_as_champion flag
// ============================================

let executionMode = 'full';
try {
  const inputData = $('Called from AI Engine').first().json;
  if (inputData && inputData.mode) executionMode = inputData.mode;
} catch(e) {}

try {
  const scheduleData = $('Set Sync Only Mode').first().json;
  if (scheduleData && scheduleData.mode) executionMode = scheduleData.mode;
} catch(e) {}

const championData = $('Get Champion Portfolio').first().json;
const champion = Array.isArray(championData) ? championData[0] : championData;

const positionsData = $('Get Champion Virtual Positions').all().map(i => i.json);
const championVirtualPositions = positionsData.flat().filter(p => p && p.id);

// Get champion's recent decision (for logging only)
let championDecision = null;
let championDecisionTime = null;
try {
  const decisionData = $('Get Champion Recent Decision').first().json;
  const decisions = Array.isArray(decisionData) ? decisionData : [decisionData];
  if (decisions.length > 0 && decisions[0]) {
    championDecision = decisions[0].action;
    championDecisionTime = decisions[0].created_at;
  }
} catch(e) {}

const aiExecutions = $('Get AI Open Executions').all().map(i => i.json).filter(e => e && e.id);
const tlPositionsData = $('Get TL Positions').first().json;
const accountData = $('Get TL Account').first().json;
const config = $('Check Config').first().json;

// ========== API ERROR CHECK ==========
const hasApiError = tlPositionsData.error || 
                   tlPositionsData.status >= 500 ||
                   (tlPositionsData.message && tlPositionsData.message.includes('504')) ||
                   (tlPositionsData.message && tlPositionsData.message.includes('timeout'));

if (hasApiError) {
  const championName = champion?.ai_models?.name || 'Unknown';
  return [{
    json: {
      action: 'SKIP_API_ERROR',
      reason: 'TradeLocker API error - skipping sync to prevent false closures',
      errorDetails: tlPositionsData.error?.message || tlPositionsData.message || 'Unknown API error',
      executionMode,
      championName,
      championModelId: champion?.model_id,
      championPortfolioId: champion?.id,
      championCurrentBalance: parseFloat(champion?.current_balance) || 10000,
      championDecision,
      currentPrice: 0,
      staleExecutionIds: [],
      summary: {
        virtualLongs: championVirtualPositions.filter(p => p.side === 'LONG' && p.status === 'OPEN').length,
        virtualShorts: championVirtualPositions.filter(p => p.side === 'SHORT' && p.status === 'OPEN').length,
        realLongs: -1,
        realShorts: -1,
        staleExecutions: 0,
        openExecutions: aiExecutions.filter(e => e.position_status === 'OPEN').length,
        orphanedPosition: false,
        orphanedPositionSide: null,
        championDecision,
        apiError: true
      }
    }
  }];
}

let currentPrice = 0;
try {
  const priceData = $('Get Current Price').first().json;
  currentPrice = parseFloat(priceData.price) || 0;
} catch(e) {}

const MIN_TP_DISTANCE = 360;
const MIN_SL_DISTANCE = 240;
const MIN_RISK_REWARD = 1.5;

const rawPositions = tlPositionsData.d?.positions || tlPositionsData.positions || [];
const tlPositions = rawPositions.map(p => {
  if (Array.isArray(p)) {
    return {
      id: String(p[0]),
      instrumentId: String(p[1]),
      side: p[3],
      qty: parseFloat(p[4]) || 0,
      avgPrice: parseFloat(p[5]) || 0,
      stopLoss: p[9] ? parseFloat(p[9]) : null,
      takeProfit: p[10] ? parseFloat(p[10]) : null
    };
  }
  return { ...p, id: String(p.id), stopLoss: p.stopLoss || null, takeProfit: p.takeProfit || null };
});

const btcTLPositions = tlPositions.filter(p => String(p.tradableInstrumentId || p.instrumentId) === '9503');
const realPositionIds = btcTLPositions.map(p => String(p.id));
const account = accountData.accounts?.[0] || {};

const staleExecutions = aiExecutions.filter(e => 
  e.position_status === 'OPEN' && 
  e.tradelocker_position_id &&
  !realPositionIds.includes(String(e.tradelocker_position_id))
);

const championName = champion?.ai_models?.name || 'Unknown';
const championModelId = champion?.model_id;

if (!championModelId) {
  return [{ json: { action: 'NONE', reason: 'No champion model found', executionMode, championName, currentPrice, staleExecutionIds: staleExecutions.map(e => e.id) } }];
}

const virtualLongs = championVirtualPositions.filter(p => p.side === 'LONG' && p.status === 'OPEN');
const virtualShorts = championVirtualPositions.filter(p => p.side === 'SHORT' && p.status === 'OPEN');
const realLongs = btcTLPositions.filter(p => p.side === 'buy');
const realShorts = btcTLPositions.filter(p => p.side === 'sell');

const openExecutions = aiExecutions.filter(e => e.position_status === 'OPEN');
let orphanedPosition = null;
let orphanedPositionSide = null;

if (btcTLPositions.length > 0) {
  for (const tlPos of btcTLPositions) {
    const matchingExec = openExecutions.find(e => 
      String(e.tradelocker_position_id) === String(tlPos.id)
    );
    if (!matchingExec) {
      orphanedPosition = tlPos;
      orphanedPositionSide = tlPos.side === 'buy' ? 'LONG' : 'SHORT';
      break;
    }
  }
}

let syncAction = 'NONE';
let syncDetails = {};

if (orphanedPosition) {
  const matchingVirtual = orphanedPositionSide === 'LONG' ? virtualLongs[0] : virtualShorts[0];

  if (!matchingVirtual) {
    syncAction = orphanedPositionSide === 'LONG' ? 'CLOSE_LONG' : 'CLOSE_SHORT';
    syncDetails = {
      reason: 'Orphaned position - no matching virtual position for current champion',
      positionId: orphanedPosition.id,
      quantity: orphanedPosition.qty,
      avgPrice: orphanedPosition.avgPrice,
      currentPrice: currentPrice,
      orphanedSide: orphanedPositionSide
    };
  } else if (!orphanedPosition.stopLoss || !orphanedPosition.takeProfit) {
    syncAction = orphanedPositionSide === 'LONG' ? 'CLOSE_LONG' : 'CLOSE_SHORT';
    syncDetails = {
      reason: 'Orphaned position missing SL/TP - closing for resync',
      positionId: orphanedPosition.id,
      quantity: orphanedPosition.qty,
      avgPrice: orphanedPosition.avgPrice,
      currentPrice: currentPrice,
      orphanedSide: orphanedPositionSide
    };
  } else {
    syncAction = 'NONE';
    syncDetails = { 
      reason: 'Orphaned position accepted - direction matches and SL/TP set',
      positionId: orphanedPosition.id,
      side: orphanedPositionSide
    };
  }
}
else if (staleExecutions.length > 0) {
  const processedPositionIds = new Set();
  const autoClosedPositions = [];

  for (const staleExec of staleExecutions) {
    const positionId = String(staleExec.tradelocker_position_id);
    if (processedPositionIds.has(positionId)) continue;
    processedPositionIds.add(positionId);

    const side = staleExec.side === 'buy' ? 'LONG' : 'SHORT';
    const entryPrice = parseFloat(staleExec.price) || 0;
    const qty = parseFloat(staleExec.quantity) || 0.03;
    const leverage = 5;
    const ROUND_TRIP_FEE = 3.18;

    const matchingVPos = championVirtualPositions.find(vp => 
      vp.side === side && vp.status === 'OPEN'
    );

    const actualSL = matchingVPos ? parseFloat(matchingVPos.stop_loss) : null;
    const actualTP = matchingVPos ? parseFloat(matchingVPos.take_profit) : null;

    let closedBy = 'AI_DECISION';
    let closedPrice = currentPrice;

    if (side === 'LONG') {
      if (actualTP && currentPrice >= actualTP) {
        closedBy = 'TP';
        closedPrice = actualTP;
      } else if (actualSL && currentPrice <= actualSL) {
        closedBy = 'SL';
        closedPrice = actualSL;
      }
    } else {
      if (actualTP && currentPrice <= actualTP) {
        closedBy = 'TP';
        closedPrice = actualTP;
      } else if (actualSL && currentPrice >= actualSL) {
        closedBy = 'SL';
        closedPrice = actualSL;
      }
    }

    let grossPnl = side === 'LONG'
      ? (closedPrice - entryPrice) * qty * leverage
      : (entryPrice - closedPrice) * qty * leverage;
    const netPnl = grossPnl - ROUND_TRIP_FEE;

    autoClosedPositions.push({
      executionId: staleExec.id,
      positionId: positionId,
      side: side,
      entryPrice,
      closedPrice,
      closedBy,
      quantity: qty,
      leverage,
      grossPnl: Math.round(grossPnl * 100) / 100,
      netPnl: Math.round(netPnl * 100) / 100,
      actualSL,
      actualTP,
      virtualPositionId: matchingVPos?.id || null
    });
  }

  if (autoClosedPositions.length > 0) {
    syncAction = 'AUTO_CLOSED_BY_SLTP';
    syncDetails = {
      positions: autoClosedPositions,
      totalPnl: autoClosedPositions.reduce((sum, p) => sum + p.netPnl, 0)
    };
  }
}
else if (executionMode === 'sync_only') {
  syncAction = 'NONE';
  syncDetails = { reason: 'Sync only mode - no position changes', executionMode };
}
// ========== v2.7: Champion decision takes priority ==========
// 1. 챔피언이 이번 라운드에 OPEN 결정을 내렸다면 즉시 실행 (opened_as_champion 무관)
else if (championDecision === 'OPEN_LONG' && realLongs.length === 0 && realShorts.length === 0 && virtualLongs.length > 0) {
  const vPos = virtualLongs[0];
  const rawSL = parseFloat(vPos.stop_loss) || null;
  const rawTP = parseFloat(vPos.take_profit) || null;
  const { stopLoss, takeProfit, slAdjusted, tpAdjusted, rrAdjusted } = validateAndFixSLTP('buy', rawSL, rawTP, currentPrice);

  syncAction = 'OPEN_LONG';
  syncDetails = {
    side: 'buy',
    quantity: parseFloat(vPos.quantity) || 0.02,
    stopLoss, takeProfit,
    originalSL: rawSL, originalTP: rawTP,
    slAdjusted, tpAdjusted, rrAdjusted,
    virtualPositionId: vPos.id,
    triggeredByChampionDecision: true,
    championDecision: championDecision
  };
}
else if (championDecision === 'OPEN_SHORT' && realShorts.length === 0 && realLongs.length === 0 && virtualShorts.length > 0) {
  const vPos = virtualShorts[0];
  const rawSL = parseFloat(vPos.stop_loss) || null;
  const rawTP = parseFloat(vPos.take_profit) || null;
  const { stopLoss, takeProfit, slAdjusted, tpAdjusted, rrAdjusted } = validateAndFixSLTP('sell', rawSL, rawTP, currentPrice);

  syncAction = 'OPEN_SHORT';
  syncDetails = {
    side: 'sell',
    quantity: parseFloat(vPos.quantity) || 0.02,
    stopLoss, takeProfit,
    originalSL: rawSL, originalTP: rawTP,
    slAdjusted, tpAdjusted, rrAdjusted,
    virtualPositionId: vPos.id,
    triggeredByChampionDecision: true,
    championDecision: championDecision
  };
}
// 2. 챔피언 결정이 없을 때만 기존 포지션 동기화 (opened_as_champion 체크)
else if (virtualLongs.length > 0 && realLongs.length === 0 && realShorts.length === 0) {
  const vPos = virtualLongs[0];

  // 기존 포지션 동기화는 opened_as_champion 필요
  if (vPos.opened_as_champion !== true) {
    syncAction = 'NONE';
    syncDetails = { 
      reason: 'Virtual LONG exists but no champion decision and not opened as champion - skipping sync',
      virtualPositionId: vPos.id,
      opened_as_champion: vPos.opened_as_champion,
      championDecision: championDecision,
      skippedSync: true
    };
  } else {
    const rawSL = parseFloat(vPos.stop_loss) || null;
    const rawTP = parseFloat(vPos.take_profit) || null;
    const { stopLoss, takeProfit, slAdjusted, tpAdjusted, rrAdjusted } = validateAndFixSLTP('buy', rawSL, rawTP, currentPrice);

    syncAction = 'OPEN_LONG';
    syncDetails = {
      side: 'buy',
      quantity: parseFloat(vPos.quantity) || 0.02,
      stopLoss, takeProfit,
      originalSL: rawSL, originalTP: rawTP,
      slAdjusted, tpAdjusted, rrAdjusted,
      virtualPositionId: vPos.id,
      triggeredByVirtualPosition: true,
      opened_as_champion: true
    };
  }
}
else if (virtualShorts.length > 0 && realShorts.length === 0 && realLongs.length === 0) {
  const vPos = virtualShorts[0];

  // 기존 포지션 동기화는 opened_as_champion 필요
  if (vPos.opened_as_champion !== true) {
    syncAction = 'NONE';
    syncDetails = { 
      reason: 'Virtual SHORT exists but no champion decision and not opened as champion - skipping sync',
      virtualPositionId: vPos.id,
      opened_as_champion: vPos.opened_as_champion,
      championDecision: championDecision,
      skippedSync: true
    };
  } else {
    const rawSL = parseFloat(vPos.stop_loss) || null;
    const rawTP = parseFloat(vPos.take_profit) || null;
    const { stopLoss, takeProfit, slAdjusted, tpAdjusted, rrAdjusted } = validateAndFixSLTP('sell', rawSL, rawTP, currentPrice);

    syncAction = 'OPEN_SHORT';
    syncDetails = {
      side: 'sell',
      quantity: parseFloat(vPos.quantity) || 0.02,
      stopLoss, takeProfit,
      originalSL: rawSL, originalTP: rawTP,
      slAdjusted, tpAdjusted, rrAdjusted,
      virtualPositionId: vPos.id,
      triggeredByVirtualPosition: true,
      opened_as_champion: true
    };
  }
}
// ========== END v2.7 ==========
else if (virtualLongs.length > 0 && realShorts.length > 0) {
  const realPos = realShorts[0];
  syncAction = 'CLOSE_SHORT';
  syncDetails = {
    reason: 'Direction mismatch - champion wants LONG but SHORT exists',
    positionId: realPos.id,
    quantity: realPos.qty,
    avgPrice: realPos.avgPrice,
    currentPrice: currentPrice,
    nextAction: 'OPEN_LONG'
  };
}
else if (virtualShorts.length > 0 && realLongs.length > 0) {
  const realPos = realLongs[0];
  syncAction = 'CLOSE_LONG';
  syncDetails = {
    reason: 'Direction mismatch - champion wants SHORT but LONG exists',
    positionId: realPos.id,
    quantity: realPos.qty,
    avgPrice: realPos.avgPrice,
    currentPrice: currentPrice,
    nextAction: 'OPEN_SHORT'
  };
}
else if (virtualLongs.length === 0 && virtualShorts.length === 0 && (realLongs.length > 0 || realShorts.length > 0)) {
  if (realLongs.length > 0) {
    const realPos = realLongs[0];
    syncAction = 'CLOSE_LONG';
    syncDetails = {
      reason: 'Champion has no position but LONG exists in TL',
      positionId: realPos.id,
      quantity: realPos.qty,
      avgPrice: realPos.avgPrice,
      currentPrice: currentPrice
    };
  } else {
    const realPos = realShorts[0];
    syncAction = 'CLOSE_SHORT';
    syncDetails = {
      reason: 'Champion has no position but SHORT exists in TL',
      positionId: realPos.id,
      quantity: realPos.qty,
      avgPrice: realPos.avgPrice,
      currentPrice: currentPrice
    };
  }
}
else {
  syncAction = 'NONE';
  syncDetails = { reason: 'Already in sync' };
}

function validateAndFixSLTP(side, sl, tp, price) {
  let finalSL = sl;
  let finalTP = tp;
  let slAdjusted = false;
  let tpAdjusted = false;
  let rrAdjusted = false;

  if (side === 'buy') {
    const minSL = price - MIN_SL_DISTANCE;
    if (!finalSL || finalSL >= price || (price - finalSL) < MIN_SL_DISTANCE) {
      finalSL = minSL;
      slAdjusted = true;
    }
    const minTP = price + MIN_TP_DISTANCE;
    if (!finalTP || finalTP <= price || (finalTP - price) < MIN_TP_DISTANCE) {
      finalTP = minTP;
      tpAdjusted = true;
    }
  } else {
    const minSL = price + MIN_SL_DISTANCE;
    if (!finalSL || finalSL <= price || (finalSL - price) < MIN_SL_DISTANCE) {
      finalSL = minSL;
      slAdjusted = true;
    }
    const minTP = price - MIN_TP_DISTANCE;
    if (!finalTP || finalTP >= price || (price - finalTP) < MIN_TP_DISTANCE) {
      finalTP = minTP;
      tpAdjusted = true;
    }
  }

  const slDistance = Math.abs(price - finalSL);
  const tpDistance = Math.abs(finalTP - price);
  const currentRR = tpDistance / slDistance;

  if (currentRR < MIN_RISK_REWARD) {
    if (side === 'buy') {
      finalTP = price + (slDistance * MIN_RISK_REWARD);
    } else {
      finalTP = price - (slDistance * MIN_RISK_REWARD);
    }
    tpAdjusted = true;
    rrAdjusted = true;
  }

  finalSL = Math.round(finalSL * 10) / 10;
  finalTP = Math.round(finalTP * 10) / 10;

  return { stopLoss: finalSL, takeProfit: finalTP, slAdjusted, tpAdjusted, rrAdjusted };
}

return [{
  json: {
    action: syncAction,
    details: syncDetails,
    executionMode,
    championName,
    championModelId,
    championPortfolioId: champion?.id,
    championCurrentBalance: parseFloat(champion?.current_balance) || 10000,
    championDecision,
    championDecisionTime,
    currentPrice,
    accessToken: config.accessToken,
    accNum: account.accNum,
    accountId: account.id,
    instrumentId: 9503,
    routeId: 1084503,
    staleExecutionIds: staleExecutions.map(e => e.id),
    summary: {
      virtualLongs: virtualLongs.length,
      virtualShorts: virtualShorts.length,
      realLongs: realLongs.length,
      realShorts: realShorts.length,
      staleExecutions: staleExecutions.length,
      openExecutions: openExecutions.length,
      orphanedPosition: !!orphanedPosition,
      orphanedPositionSide,
      championDecision
    }
  }
}];

