const orderResult = $('Open Position Order').first().json;
const positionsData = $('Get New Position').first().json;
const syncData = $('Sync Analysis').first().json;

const isSuccess = orderResult.s?.toLowerCase() === 'ok';

let positionId = null;
if (isSuccess) {
  const positions = positionsData.d?.positions || [];
  for (const pos of positions) {
    const p = Array.isArray(pos) ? { id: pos[0], instrumentId: pos[1] } : pos;
    if (String(p.tradableInstrumentId || p.instrumentId) === '9503') {
      positionId = String(p.id);
    }
  }
}

// ⭐ 실제 체결가 기준으로 SL/TP 재계산
const actualPrice = parseFloat(orderResult.d?.averagePrice) || syncData.currentPrice || 0;
const originalPrice = syncData.currentPrice || actualPrice;
const priceDiff = actualPrice - originalPrice;

const MIN_SL_DISTANCE = 240;
const MIN_TP_DISTANCE = 360;
const MIN_RISK_REWARD = 1.5;

// ⭐ 슬리피지 조정 함수 (최소 거리 유지)
function adjustSLTPForSlippage(side, originalSL, originalTP, originalPrice, actualPrice) {
  let adjustedSL = originalSL;
  let adjustedTP = originalTP;
  let slAdjusted = false;
  let tpAdjusted = false;

  // 슬리피지가 $1 이상일 때만 조정
  if (Math.abs(actualPrice - originalPrice) > 1) {
    if (side === 'buy') {
      // LONG: TP는 그대로 이동, SL은 최소 거리 유지
      adjustedTP = originalTP + (actualPrice - originalPrice);

      // SL은 최소 거리를 확보하도록 조정
      const minSL = actualPrice - MIN_SL_DISTANCE;
      adjustedSL = Math.min(originalSL, minSL);

      tpAdjusted = true;
      slAdjusted = (adjustedSL !== originalSL);
    } else {
      // SHORT: TP는 그대로 이동, SL은 최소 거리 유지
      adjustedTP = originalTP - (actualPrice - originalPrice);

      // SL은 최소 거리를 확보하도록 조정
      const minSL = actualPrice + MIN_SL_DISTANCE;
      adjustedSL = Math.max(originalSL, minSL);

      tpAdjusted = true;
      slAdjusted = (adjustedSL !== originalSL);
    }
  }

  // 최종 validation (R:R 비율 체크)
  const slDistance = Math.abs(actualPrice - adjustedSL);
  const tpDistance = Math.abs(adjustedTP - actualPrice);
  const currentRR = tpDistance / slDistance;

  if (currentRR < MIN_RISK_REWARD) {
    // R:R이 나쁘면 TP를 늘림
    if (side === 'buy') {
      adjustedTP = actualPrice + (slDistance * MIN_RISK_REWARD);
    } else {
      adjustedTP = actualPrice - (slDistance * MIN_RISK_REWARD);
    }
    tpAdjusted = true;
  }

  // 소수점 한자리로 반올림
  adjustedSL = Math.round(adjustedSL * 10) / 10;
  adjustedTP = Math.round(adjustedTP * 10) / 10;

  return { adjustedSL, adjustedTP, slAdjusted, tpAdjusted };
}

let finalSL = syncData.details.stopLoss;
let finalTP = syncData.details.takeProfit;
let slAdjustedBySlippage = false;
let tpAdjustedBySlippage = false;

if (isSuccess && actualPrice > 0) {
  const result = adjustSLTPForSlippage(
    syncData.details.side,
    syncData.details.stopLoss,
    syncData.details.takeProfit,
    originalPrice,
    actualPrice
  );

  finalSL = result.adjustedSL;
  finalTP = result.adjustedTP;
  slAdjustedBySlippage = result.slAdjusted;
  tpAdjustedBySlippage = result.tpAdjusted;
}

return [{
  json: {
    symbol: 'BTCUSD',
    action: syncData.action,
    side: syncData.details.side,
    quantity: syncData.details.quantity,
    price: actualPrice,
    tradelocker_order_id: String(orderResult.d?.orderId || ''),
    tradelocker_position_id: positionId,
    position_status: isSuccess ? 'OPEN' : 'FAILED',
    status: isSuccess ? 'FILLED' : 'FAILED',
    champion_model_id: syncData.championModelId,
    error_message: orderResult.errmsg || null,
    executed_at: new Date().toISOString(),
    championName: syncData.championName,
    currentPrice: syncData.currentPrice,
    actualPrice: actualPrice,
    priceDiff: Math.round(priceDiff * 100) / 100,
    stopLoss: finalSL,
    takeProfit: finalTP,
    originalSL: syncData.details.originalSL,
    originalTP: syncData.details.originalTP,
    slAdjusted: slAdjustedBySlippage || syncData.details.slAdjusted || false,
    tpAdjusted: tpAdjustedBySlippage || syncData.details.tpAdjusted || false,
    rrAdjusted: syncData.details.rrAdjusted || false,
    slAdjustedBySlippage: slAdjustedBySlippage,
    tpAdjustedBySlippage: tpAdjustedBySlippage,
    summary: syncData.summary
  }
}];

const orderResult = $('Close Position Order').first().json;
const syncData = $('Sync Analysis').first().json;

// DELETE 요청 성공 여부 확인
// TradeLocker DELETE는 성공 시 s: 'ok' 또는 빈 응답
const isSuccess = orderResult.s?.toLowerCase() === 'ok' || 
                  orderResult.status === 'ok' ||
                  !orderResult.error;

return [{
  json: {
    symbol: 'BTCUSD',
    action: syncData.action,
    side: syncData.details.side,
    quantity: syncData.details.quantity,
    price: syncData.currentPrice || 0,
    tradelocker_order_id: null,
    tradelocker_position_id: syncData.details.positionId,
    position_status: 'CLOSED',
    status: isSuccess ? 'FILLED' : 'FAILED',
    champion_model_id: syncData.championModelId,
    error_message: orderResult.errmsg || orderResult.error || null,
    executed_at: new Date().toISOString(),
    championName: syncData.championName,
    summary: syncData.summary,
    closeExecutionId: syncData.details.executionId,
    deleteResponse: orderResult
  }
}];

