  let slValue = originalData.stopLoss || d.stopLoss;
  let tpValue = originalData.takeProfit || d.takeProfit;
  let championName = originalData.championName || d.championName;
  const summary = originalData.summary || d.summary || {};

  const actionIcon = d.action === 'OPEN_LONG' ? '🟢' : 
                     d.action === 'OPEN_SHORT' ? '🔴' : 
                     d.action === 'CLOSE_LONG' ? '🟢' : 
                     d.action === 'CLOSE_SHORT' ? '🔴' : '⚪';

  const statusIcon = d.status === 'FILLED' ? '✅' : '❌';

  let msg = statusIcon + ' <b>Position Sync Executed</b>\n\n';
  msg += '🏆 Champion: <b>' + (championName || 'Unknown') + '</b>\n';
  msg += actionIcon + ' Action: <b>' + d.action + '</b>\n\n';

  msg += '📊 <b>Order Details</b>\n';
  msg += '• Symbol: BTCUSD\n';
  msg += '• Side: ' + d.side + '\n';
  msg += '• Size: ' + d.quantity + ' lot\n';
  msg += '• Price: $' + Math.round(originalData.actualPrice || d.price) + '\n';
  msg += '• Status: ' + d.status + '\n';

  if (d.action && d.action.includes('OPEN') && slValue && tpValue) {
    msg += '\n🎯 <b>SL/TP</b>\n';
    msg += '• SL: $' + Math.round(slValue) + '\n';
    msg += '• TP: $' + Math.round(tpValue) + '\n';

    const adjustments = [];
    if (originalData.slAdjusted) adjustments.push('SL adjusted');
    if (originalData.tpAdjusted) adjustments.push('TP adjusted');
    if (originalData.rrAdjusted) adjustments.push('R:R enforced (min 1:1.5)');

    if (adjustments.length > 0) {
      msg += '\n⚙️ <b>Adjustments:</b>\n';
      adjustments.forEach(adj => { msg += '• ' + adj + '\n'; });
    }
  }

  // Sync State (After) - 진입 후에는 +1 표시
  let vLongs = summary.virtualLongs || 0;
  let vShorts = summary.virtualShorts || 0;
  let rLongs = summary.realLongs || 0;
  let rShorts = summary.realShorts || 0;

  // OPEN 액션 후에는 Real에 +1
  if (d.action === 'OPEN_LONG' && d.status === 'FILLED') rLongs += 1;
  if (d.action === 'OPEN_SHORT' && d.status === 'FILLED') rShorts += 1;
  // CLOSE 액션 후에는 Real에 -1 (이미 0이면 그대로)
  if (d.action === 'CLOSE_LONG' && d.status === 'FILLED') rLongs = Math.max(0, rLongs - 1);
  if (d.action === 'CLOSE_SHORT' && d.status === 'FILLED') rShorts = Math.max(0, rShorts - 1);

  msg += '\n📈 <b>Sync State (After)</b>\n';
  msg += 'Virtual: ' + vLongs + 'L / ' + vShorts + 'S\n';
  msg += 'Real: ' + rLongs + 'L / ' + rShorts + 'S\n';

  msg += '\n⏰ ' + new Date().toISOString().substring(11,19) + ' UTC';

  return JSON.stringify({chat_id: '-1003644771027', parse_mode: 'HTML', text: msg});
})() }}

