const data = $input.first().json;
const staleIds = data.staleExecutionIds || [];

if (staleIds.length === 0) {
  return [$input.first()];
}

const API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRuZGF2ZnZma2tsbXVkYnBmZGhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc4OTc5MjgsImV4cCI6MjA4MzQ3MzkyOH0.TbFIFNUnYACyAT8c_vl3agifPPx8ut0OcCoz6JJ2aBY';

let cleanedCount = 0;

for (const execId of staleIds) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://tndavfvfkklmudbpfdhj.supabase.co/rest/v1/trade_executions?id=eq.${execId}`,
      headers: {
        'apikey': API_KEY,
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: { position_status: 'CLOSED', error_message: 'Auto-closed: Position not found in TradeLocker' },
      json: true
    });
    cleanedCount++;
  } catch(e) {}
}

return [{ json: { ...data, cleanedStaleExecutions: cleanedCount } }];

// symbol이 없으면 스킵
const data = $input.first()?.json;
if (!data || !data.symbol) {
  return [];
}
return [$input.first()];

// Set SL/TP 후 Prepare Open Save 데이터 복원
const openData = $('Prepare Open Save').first().json;
const sltpResult = $input.first().json;

return [{
  json: {
    ...openData,
    sltpSet: sltpResult.s === 'ok'
  }
}];

// ============================================
// TP/SL 자동 청산 처리 (TradeLocker History 기반)
// v2.6 - CLOSE 기록 INSERT 추가
// ============================================

const data = $input.first().json;
const positions = data.details?.positions || [];

if (positions.length === 0) {
  return [{ json: { ...data, processed: false, reason: 'No positions to process' } }];
}

const API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRuZGF2ZnZma2tsbXVkYnBmZGhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc4OTc5MjgsImV4cCI6MjA4MzQ3MzkyOH0.TbFIFNUnYACyAT8c_vl3agifPPx8ut0OcCoz6JJ2aBY';
const BASE_URL = 'https://tndavfvfkklmudbpfdhj.supabase.co/rest/v1';

const results = [];
let actualPnlToApply = 0;
let actualTradeCount = 0;
let actualWinCount = 0;

for (const pos of positions) {
  let updated = false;
  let error = null;
  let virtualPositionUpdated = false;
  let alreadyClosed = false;
  let closeRecordInserted = false;

  try {
    // 1. virtual_positions 상태 확인
    if (pos.virtualPositionId) {
      const vpRes = await this.helpers.httpRequest({
        method: 'GET',
        url: `${BASE_URL}/virtual_positions?id=eq.${pos.virtualPositionId}`,
        headers: {
          'apikey': API_KEY,
          'Authorization': `Bearer ${API_KEY}`
        },
        json: true
      });

      const vp = vpRes[0];

      if (vp && vp.status === 'CLOSED') {
        alreadyClosed = true;
      } else if (vp && vp.status === 'OPEN') {
        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${BASE_URL}/virtual_positions?id=eq.${pos.virtualPositionId}`,
          headers: {
            'apikey': API_KEY,
            'Authorization': `Bearer ${API_KEY}`,
            'Content-Type': 'application/json',
            'Prefer': 'return=minimal'
          },
          body: {
            status: 'CLOSED',
            closed_at: new Date().toISOString(),
            close_price: pos.closedPrice,
            realized_pnl: pos.netPnl
          },
          json: true
        });
        virtualPositionUpdated = true;

        actualPnlToApply += (parseFloat(pos.netPnl) || 0);
        actualTradeCount += 1;
        if ((parseFloat(pos.netPnl) || 0) > 0) actualWinCount += 1;
      }
    }

    // 2. trade_executions - 기존 OPEN 기록 PATCH
    if (pos.executionId) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${BASE_URL}/trade_executions?id=eq.${pos.executionId}`,
        headers: {
          'apikey': API_KEY,
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: {
          position_status: 'CLOSED'
        },
        json: true
      });
    }

    // 3. NEW: trade_executions - CLOSE 기록 INSERT
    if (!alreadyClosed) {
      const closeAction = pos.side === 'LONG' ? 'CLOSE_LONG' : 'CLOSE_SHORT';
      const closeSide = pos.side === 'LONG' ? 'buy' : 'sell';

      await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/trade_executions`,
        headers: {
          'apikey': API_KEY,
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: {
          symbol: 'BTCUSD',
          action: closeAction,
          side: closeSide,
          quantity: pos.quantity,
          price: pos.closedPrice,
          tradelocker_position_id: pos.positionId,
          position_status: 'CLOSED',
          status: 'FILLED',
          champion_model_id: data.championModelId,
          error_message: `Auto-closed by ${pos.closedBy} at $${pos.closedPrice}`,
          executed_at: new Date().toISOString()
        },
        json: true
      });
      closeRecordInserted = true;
    }

    updated = true;
  } catch(e) {
    error = e.message;
  }

  results.push({ ...pos, updated, error, virtualPositionUpdated, alreadyClosed, closeRecordInserted });
}

// 4. virtual_portfolios 잔고 업데이트
const portfolioId = data.championPortfolioId;
let portfolioUpdated = false;
let balanceAlreadyUpdated = false;
let newBalance = parseFloat(data.championCurrentBalance);

if (portfolioId && actualPnlToApply !== 0 && actualTradeCount > 0) {
  try {
    const portfolioRes = await this.helpers.httpRequest({
      method: 'GET',
      url: `${BASE_URL}/virtual_portfolios?id=eq.${portfolioId}`,
      headers: {
        'apikey': API_KEY,
        'Authorization': `Bearer ${API_KEY}`
      },
      json: true
    });

    const portfolio = portfolioRes[0];
    const currentBalance = parseFloat(portfolio?.current_balance) || 10000;
    const currentTrades = parseInt(portfolio?.total_trades) || 0;
    const currentWins = parseInt(portfolio?.winning_trades) || 0;
    const currentRealizedPnl = parseFloat(portfolio?.realized_pnl) || 0;

    newBalance = currentBalance + actualPnlToApply;

    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${BASE_URL}/virtual_portfolios?id=eq.${portfolioId}`,
      headers: {
        'apikey': API_KEY,
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: {
        current_balance: Math.round(newBalance * 100) / 100,
        realized_pnl: Math.round((currentRealizedPnl + actualPnlToApply) * 100) / 100,
        total_trades: currentTrades + actualTradeCount,
        winning_trades: currentWins + actualWinCount,
        updated_at: new Date().toISOString()
      },
      json: true
    });

    portfolioUpdated = true;
  } catch(e) {}
} else {
  balanceAlreadyUpdated = true;
}

const totalPnl = positions.reduce((sum, p) => sum + (parseFloat(p.netPnl) || 0), 0);
const alreadyClosedCount = results.filter(r => r.alreadyClosed).length;
const closeRecordsInserted = results.filter(r => r.closeRecordInserted).length;

return [{
  json: {
    action: 'AUTO_CLOSED_BY_SLTP',
    championName: data.championName,
    championModelId: data.championModelId,
    processedPositions: results,
    totalPnl: Math.round(totalPnl * 100) / 100,
    actualPnlApplied: Math.round(actualPnlToApply * 100) / 100,
    previousBalance: parseFloat(data.championCurrentBalance),
    newBalance: Math.round(newBalance * 100) / 100,
    positionsCount: positions.length,
    alreadyClosedCount: alreadyClosedCount,
    actuallyProcessedCount: actualTradeCount,
    closeRecordsInserted: closeRecordsInserted,
    winsCount: actualWinCount,
    portfolioUpdated,
    balanceAlreadyUpdated,
    summary: data.summary
  }
}];

